def _sanitize_blob_path(p: str) -> str:
    p = (p or "").strip()
    p = p.lstrip("/")

    if not p:
        raise ValueError("Missing blob path.")

    if "\x00" in p:
        raise ValueError("Invalid blob path.")

    parts = [seg for seg in p.split("/") if seg not in ("", ".")]
    if any(seg == ".." for seg in parts):
        raise ValueError("Invalid blob path.")

    return "/".join(parts)

def _guess_content_type(blob_name: str, content_type_from_blob: str | None) -> str:
    if content_type_from_blob:
        return content_type_from_blob
    ct, _ = mimetypes.guess_type(blob_name)
